1	import { InjectQueue } from '@nestjs/bullmq';
2	import { Injectable, Logger } from '@nestjs/common';
3	import { Queue } from 'bullmq';
4	
5	import { JiraChangelogModel } from '@modules/jira/db/jira-changelog.model';
6	import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
7	import { JiraIssueModel } from '@modules/jira/db/jira-issues.model';
8	import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
9	import { JiraSprintModel } from '@modules/jira/db/jira-sprints.model';
10	import { JiraWorklogModel } from '@modules/jira/db/jira-worklogs.model';
11	import { JiraApiService } from '@modules/jira/jira-api.service';
12	import { IJiraApiIssue } from '@modules/jira/types/jira-api.interface';
13	import { IJiraIssueBase } from '@modules/jira/types/jira-installation.interface';
14	
15	const THREE_YEARS_MS = 3 * 365 * 24 * 60 * 60 * 1000;
16	
17	@Injectable()
18	export class JiraSyncService {
19		private readonly logger = new Logger(JiraSyncService.name);
20	
21		constructor(
22			private readonly installationModel: JiraInstallationModel,
23			private readonly projectModel: JiraProjectModel,
24			private readonly issueModel: JiraIssueModel,
25			private readonly changelogModel: JiraChangelogModel,
26			private readonly worklogModel: JiraWorklogModel,
27			private readonly sprintModel: JiraSprintModel,
28			private readonly jiraApiService: JiraApiService,
29			@InjectQueue('jira') private readonly jiraQueue: Queue,
30		) {}
31	
32		async discoverProjects({
33			installationDbId,
34		}: {
35			installationDbId: string;
36		}): Promise<void> {
37			const installation = await this.installationModel.findById({ id: installationDbId });
38	
39			if (!installation) {
40				this.logger.warn(`Installation ${installationDbId} not found`);
41				return;
42			}
43	
44			const token = await this.jiraApiService.getValidToken({ installation });
45			const projects = await this.jiraApiService.listProjects({
46				cloudId: installation.cloud_id,
47				token,
48			});
49	
50			await this.projectModel.upsertMany({ installationId: installationDbId, projects });
51	
52			const savedProjects = await this.projectModel.findByInstallationId({
53				installationId: installationDbId,
54			});
55	
56			for (const project of savedProjects) {
57				await this.jiraQueue.add(
58					'sync_project',
59					{
60						installationDbId,
61						projectDbId: project._id,
62						projectKey: project.project_key,
63						projectId: project.project_id,
64					},
65					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
66				);
67			}
68	
69			this.logger.debug(
70				`Enqueued sync for ${savedProjects.length} projects in installation ${installationDbId}`,
71			);
72		}
73	
74		async syncProject({
75			installationDbId,
76			projectDbId,
77			projectKey,
78		}: {
79			installationDbId: string;
80			projectDbId: string;
81			projectKey: string;
82		}): Promise<void> {
83			const installation = await this.installationModel.findById({ id: installationDbId });
84	
85			if (!installation) {
86				this.logger.warn(`Installation ${installationDbId} not found`);
87				return;
88			}
89	
90			const projects = await this.projectModel.findByInstallationId({
91				installationId: installationDbId,
92			});
93			const project = projects.find((p) => p._id === projectDbId);
94	
95			if (!project) {
96				this.logger.warn(`Project ${projectDbId} not found`);
97				return;
98			}
99	
100			const token = await this.jiraApiService.getValidToken({ installation });
101	
102			const since = project.last_synced_at
103				? project.last_synced_at
104				: new Date(Date.now() - THREE_YEARS_MS);
105	
106			const sinceStr = since.toISOString().split('T')[0] ?? since.toISOString();
107			const jql = `project = "${projectKey}" AND updated >= "${sinceStr}" ORDER BY updated ASC`;
108	
109			await this.fetchAndStoreIssues({
110				installationDbId,
111				projectDbId,
112				cloudId: installation.cloud_id,
113				token,
114				jql,
115			});
116	
117			await this.fetchAndStoreSprints({
118				installationDbId,
119				projectKey,
120				cloudId: installation.cloud_id,
121				token,
122			});
123	
124			await this.projectModel.updateLastSyncedAt({ id: projectDbId });
125	
126			this.logger.debug(
127				`Sync complete for project ${projectKey} in installation ${installationDbId}`,
128			);
129		}
130	
131		async pollAllInstallations(): Promise<void> {
132			const installations = await this.installationModel.findAllActive();
133	
134			for (const installation of installations) {
135				await this.jiraQueue.add(
136					'discover_projects',
137					{ installationDbId: installation._id },
138					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
139				);
140			}
141	
142			this.logger.debug(
143				`Triggered discover_projects for ${installations.length} active installations`,
144			);
145		}
