147		private async fetchAndStoreIssues({
148			installationDbId,
149			projectDbId,
150			cloudId,
151			token,
152			jql,
153		}: {
154			installationDbId: string;
155			projectDbId: string;
156			cloudId: string;
157			token: string;
158			jql: string;
159		}): Promise<void> {
160			let startAt = 0;
161			const pageSize = 100;
162	
163			while (true) {
164				const response = await this.jiraApiService.searchIssues({
165					cloudId,
166					token,
167					jql,
168					startAt,
169				});
170	
171				if (response.issues.length === 0) break;
172	
173				const savedIssues = await this.issueModel.upsertMany({
174					issues: response.issues.map((issue) => ({
175						installation_id: installationDbId,
176						project_id: projectDbId,
177						issue_key: issue.key,
178						issue_id: issue.id,
179						issue_type: issue.fields.issuetype?.name ?? null,
180						status: issue.fields.status?.name ?? null,
181						priority: issue.fields.priority?.name ?? null,
182						assignee_id: issue.fields.assignee?.accountId ?? null,
183						reporter_id: issue.fields.reporter?.accountId ?? null,
184						story_points: issue.fields.customfield_10016 ?? null,
185						updated_at: new Date(issue.fields.updated),
186						resolved_at: issue.fields.resolutiondate
187							? new Date(issue.fields.resolutiondate)
188							: null,
189					})),
190				});
191	
192				await this.storeChangelogs({
193					installationDbId,
194					issues: response.issues,
195					savedIssues,
196				});
197	
198				await this.storeWorklogs({
199					installationDbId,
200					cloudId,
201					token,
202					issues: response.issues,
203					savedIssues,
204				});
205	
206				startAt += pageSize;
207				if (startAt >= response.total || response.issues.length < pageSize) break;
208			}
209		}
210	
211		private async storeChangelogs({
212			installationDbId,
213			issues,
214			savedIssues,
215		}: {
216			installationDbId: string;
217			issues: IJiraApiIssue[];
218			savedIssues: IJiraIssueBase[];
219		}): Promise<void> {
220			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
221			const entries: {
222				issue_id: string;
223				installation_id: string;
224				jira_history_id: string;
225				author_id: string | null;
226				field: string;
227				from_value: string | null;
228				to_value: string | null;
229				changed_at: Date;
230			}[] = [];
231	
232			for (const issue of issues) {
233				const issueDbId = issueDbIdMap.get(issue.id);
234				if (!issueDbId || !issue.changelog) continue;
235	
236				for (const history of issue.changelog.histories) {
237					for (const item of history.items) {
238						entries.push({
239							issue_id: issueDbId,
240							installation_id: installationDbId,
241							jira_history_id: history.id,
242							author_id: history.author?.accountId ?? null,
243							field: item.field,
244							from_value: item.fromString,
245							to_value: item.toString,
246							changed_at: new Date(history.created),
247						});
248					}
249				}
250			}
251	
252			await this.changelogModel.upsertMany({ entries });
253		}
254	
255		private async storeWorklogs({
256			installationDbId,
257			cloudId,
258			token,
259			issues,
260			savedIssues,
261		}: {
262			installationDbId: string;
263			cloudId: string;
264			token: string;
265			issues: IJiraApiIssue[];
266			savedIssues: IJiraIssueBase[];
267		}): Promise<void> {
268			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
269	
270			for (const issue of issues) {
271				const issueDbId = issueDbIdMap.get(issue.id);
272				if (!issueDbId) continue;
273	
274				const worklogs = await this.jiraApiService.getWorklogsForIssue({
275					cloudId,
276					token,
277					issueId: issue.id,
278				});
279	
280				if (worklogs.length === 0) continue;
281	
282				await this.worklogModel.upsertMany({
283					worklogs: worklogs.map((w) => ({
284						issue_id: issueDbId,
285						installation_id: installationDbId,
286						jira_worklog_id: w.id,
287						author_id: w.author?.accountId ?? null,
288						time_spent_sec: w.timeSpentSeconds,
289						started_at: w.started ? new Date(w.started) : null,
290						updated_at: new Date(w.updated),
291					})),
292				});
293			}
294		}
295	
296		private async fetchAndStoreSprints({
297			installationDbId,
298			projectKey,
299			cloudId,
300			token,
301		}: {
302			installationDbId: string;
303			projectKey: string;
304			cloudId: string;
305			token: string;
306		}): Promise<void> {
307			try {
308				const boardsResponse = await this.jiraApiService.listBoards({
309					cloudId,
310					token,
311					projectKeyOrId: projectKey,
312				});
313	
314				for (const board of boardsResponse.values) {
315					let startAt = 0;
316					while (true) {
317						const sprintResponse = await this.jiraApiService.listSprints({
318							cloudId,
319							token,
320							boardId: board.id,
321							startAt,
322						});
323	
324						await this.sprintModel.upsertMany({
325							installationId: installationDbId,
326							boardId: String(board.id),
327							sprints: sprintResponse.values,
328						});
329	
330						if (sprintResponse.isLast || sprintResponse.values.length === 0) break;
331						startAt += 50;
332					}
333				}
334			} catch (error) {
335				this.logger.warn(
336					`Failed to fetch sprints for project ${projectKey}: ${(error as Error).message}`,
337				);
338			}
339		}
340	}
