1	import { HttpService } from '@nestjs/axios';
2	import { Injectable, Logger } from '@nestjs/common';
3	
4	import { EnvConfigService } from '@modules/env-config/env-config.service';
5	import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
6	import {
7		IAtlassianResource,
8		IAtlassianTokenResponse,
9		IJiraApiBoardResponse,
10		IJiraApiProject,
11		IJiraApiSearchResponse,
12		IJiraApiSprintResponse,
13		IJiraApiWorklog,
14	} from '@modules/jira/types/jira-api.interface';
15	import { IJiraInstallationBase } from '@modules/jira/types/jira-installation.interface';
16	
17	import {
18		JIRA_CLIENT_ID,
19		JIRA_CLIENT_SECRET,
20		JIRA_CALLBACK_URL,
21	} from '@constants/env-variables.constant';
22	
23	const TOKEN_REFRESH_BUFFER_MS = 5 * 60 * 1000;
24	const ATLASSIAN_TOKEN_URL = 'https://auth.atlassian.com/oauth/token';
25	const ATLASSIAN_RESOURCES_URL =
26		'https://api.atlassian.com/oauth/token/accessible-resources';
27	
28	@Injectable()
29	export class JiraApiService {
30		private readonly logger = new Logger(JiraApiService.name);
31	
32		constructor(
33			private readonly httpService: HttpService,
34			private readonly configService: EnvConfigService,
35			private readonly installationModel: JiraInstallationModel,
36		) {}
37	
38		async exchangeCode({ code }: { code: string }): Promise<IAtlassianTokenResponse> {
39			const { data } = await this.httpService.axiosRef.post<IAtlassianTokenResponse>(
40				ATLASSIAN_TOKEN_URL,
41				{
42					grant_type: 'authorization_code',
43					client_id: this.configService.get<string>({ key: JIRA_CLIENT_ID }),
44					client_secret: this.configService.get<string>({ key: JIRA_CLIENT_SECRET }),
45					redirect_uri: this.configService.get<string>({ key: JIRA_CALLBACK_URL }),
46					code,
47				},
48			);
49			return data;
50		}
51	
52		async getAccessibleResources({
53			accessToken,
54		}: {
55			accessToken: string;
56		}): Promise<IAtlassianResource[]> {
57			const { data } = await this.httpService.axiosRef.get<IAtlassianResource[]>(
58				ATLASSIAN_RESOURCES_URL,
59				{ headers: { Authorization: `Bearer ${accessToken}` } },
60			);
61			return data;
62		}
63	
64		async getValidToken({
65			installation,
66		}: {
67			installation: IJiraInstallationBase;
68		}): Promise<string> {
69			const expiresAt = new Date(installation.token_expires_at).getTime();
70			const now = Date.now();
71	
72			if (expiresAt - now > TOKEN_REFRESH_BUFFER_MS) {
73				return installation.access_token;
74			}
75	
76			try {
77				const refreshed = await this.refreshToken({
78					refreshToken: installation.refresh_token,
79				});
80	
81				const tokenExpiresAt = new Date(Date.now() + refreshed.expires_in * 1000);
82	
83				await this.installationModel.updateTokens({
84					id: installation._id,
85					accessToken: refreshed.access_token,
86					refreshToken: refreshed.refresh_token,
87					tokenExpiresAt,
88				});
89	
90				this.logger.debug(`Refreshed token for installation ${installation._id}`);
91				return refreshed.access_token;
92			} catch (error) {
93				await this.installationModel.markNeedsReauth({ id: installation._id });
94				this.logger.error(
95					`Token refresh failed for installation ${installation._id}: ${(error as Error).message}`,
96				);
97				throw error;
98			}
99		}
100	
101		async listProjects({
102			cloudId,
103			token,
104		}: {
105			cloudId: string;
106			token: string;
107		}): Promise<IJiraApiProject[]> {
108			const base = this.apiBase({ cloudId });
109			const projects: IJiraApiProject[] = [];
110			let startAt = 0;
111			const maxResults = 50;
112	
113			while (true) {
114				const { data } = await this.httpService.axiosRef.get<{
115					values: IJiraApiProject[];
116					isLast: boolean;
117				}>(`${base}/project/search`, {
118					headers: { Authorization: `Bearer ${token}` },
119					params: { startAt, maxResults, typeKey: 'software' },
120				});
121	
122				projects.push(...data.values);
123				if (data.isLast || data.values.length === 0) break;
124				startAt += maxResults;
125			}
126	
127			return projects;
128		}
129	
130		async searchIssues({
131			cloudId,
132			token,
133			jql,
134			startAt,
135		}: {
136			cloudId: string;
137			token: string;
138			jql: string;
139			startAt: number;
140		}): Promise<IJiraApiSearchResponse> {
141			const base = this.apiBase({ cloudId });
142			const { data } = await this.httpService.axiosRef.post<IJiraApiSearchResponse>(
143				`${base}/search/jql`,
144				{
145					jql,
146					startAt,
147					maxResults: 100,
148					expand: ['changelog'],
149					fields: [
150						'summary',
151						'issuetype',
152						'status',
153						'priority',
154						'assignee',
155						'reporter',
156						'customfield_10016',
157						'resolutiondate',
158						'created',
159						'updated',
160					],
161				},
162				{ headers: { Authorization: `Bearer ${token}` } },
163			);
164			return data;
165		}
166	
167		async getWorklogsForIssue({
168			cloudId,
169			token,
170			issueId,
171		}: {
172			cloudId: string;
173			token: string;
174			issueId: string;
175		}): Promise<IJiraApiWorklog[]> {
176			const base = this.apiBase({ cloudId });
177			const { data } = await this.httpService.axiosRef.get<{
178				worklogs: IJiraApiWorklog[];
179			}>(`${base}/issue/${issueId}/worklog`, {
180				headers: { Authorization: `Bearer ${token}` },
181				params: { maxResults: 5000 },
182			});
183			return data.worklogs;
184		}
185	
186		async listBoards({
187			cloudId,
188			token,
189			projectKeyOrId,
190		}: {
191			cloudId: string;
192			token: string;
193			projectKeyOrId: string;
194		}): Promise<IJiraApiBoardResponse> {
195			const agileBase = this.agileBase({ cloudId });
196			const { data } = await this.httpService.axiosRef.get<IJiraApiBoardResponse>(
197				`${agileBase}/board`,
198				{
199					headers: { Authorization: `Bearer ${token}` },
200					params: { projectKeyOrId, maxResults: 50 },
201				},
202			);
203			return data;
204		}
205	
206		async listSprints({
207			cloudId,
